from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismUsdDepartmentLayerPathNode(BaseNode):
    name = "Prism USD: New Department Layer Path"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="mod")
        self.add_output("layer_path", "string")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        dept = inputs.get('department') or ''
        if core is None:
            self.log_error("No PrismCore provided.")
            return {'layer_path': '', 'success': False}
        try:
            plugin = core.getPlugin('USD') if hasattr(core, 'getPlugin') else core.plugins.getPlugin('USD')
            if plugin is None:
                self.log_error("USD plugin not loaded.")
                return {'layer_path': '', 'success': False}
            path = str(plugin.api.getNewDepartmentLayerPath(entity=entity, department=dept) or '')
            self.log_success(f"Department layer path: {path}")
            return {'layer_path': path, 'success': True}
        except Exception as e:
            self.log_error(f"getNewDepartmentLayerPath failed: {e}")
            return {'layer_path': '', 'success': False}

def register_node():
    return PrismUsdDepartmentLayerPathNode
